async (params, browser) => {
  // Open product page
  await browser.open(`${params.product_url}`)

  // Wait for page
  await browser.waitForSelector('h1, [class*=\'product-title\']', 15000)

  await browser.wait(2000)

  // Scroll to reviews
  await browser.scroll({ direction: 'down', amount: 4000 })

  await browser.wait(2000)

  // Scroll through reviews
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Extract reviews
  const reviews_data = await browser.evaluate(`const reviews = []; const reviewEls = document.querySelectorAll('[class*="feedback-item"], [class*="review-item"], [class*="ReviewItem"]'); for (let i = 0; i < Math.min(reviewEls.length, 20); i++) { const el = reviewEls[i]; const authorEl = el.querySelector('[class*="user-name"], [class*="name"]'); const ratingEl = el.querySelector('[class*="star"], [class*="rating"]'); const contentEl = el.querySelector('[class*="buyer-feedback"], [class*="review-content"], [class*="content"]'); const dateEl = el.querySelector('[class*="date"], time'); const countryEl = el.querySelector('[class*="country"], [class*="flag"]'); const hasPhoto = !!el.querySelector('[class*="photo"] img, [class*="image"] img'); reviews.push({ author: authorEl ? authorEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', content: contentEl ? contentEl.textContent.trim().substring(0, 800) : '', date: dateEl ? dateEl.textContent.trim() : '', country: countryEl ? countryEl.textContent.trim() : '', has_photo: hasPhoto }); } const overallRatingEl = document.querySelector('[class*="overview-rating"], [class*="score"]'); return { overall_rating: overallRatingEl ? overallRatingEl.textContent.trim() : '', review_count: reviews.length, reviews: reviews, url: window.location.href }`)

  return reviews_data
}
